tool.command:
exec 3>&1 4>&2; exec > enzywizard.log 2>&1; trap 'echo "---- EnzyWizard command interrupted/terminated ----" >&4; [ -f enzywizard.log ] && tail -n 300 enzywizard.log >&4; exit 143' TERM INT;
MSMS_EXE=\$(command -v msms || command -v msms.x86_64Linux2.2.6.1 || true); if [ -n "\$MSMS_EXE" ]; then mkdir -p "\$HOME"; echo "set pyvol_msms_exe, \$MSMS_EXE" > "\$HOME/.pymolrc"; fi;
mkdir -p tmp; export TMPDIR="\$PWD/tmp"; export TEMP="\$TMPDIR"; export TMP="\$TMPDIR"; export QT_QPA_PLATFORM=offscreen; export LIBGL_ALWAYS_SOFTWARE=1; export PYOPENGL_PLATFORM=osmesa; mkdir -p python_compat; printf '%s\n' 'import sys, types, io' 'try:' ' import numpy as np' ' if not hasattr(np, "float_"): np.float_ = np.float64' 'except Exception: pass' 'm = types.ModuleType("rdkit.six")' 'm.StringIO = io.StringIO' 'sys.modules.setdefault("rdkit.six", m)' 'try:' ' import rdkit; setattr(rdkit, "six", m)' 'except Exception: pass' > python_compat/sitecustomize.py; export PYTHONPATH="\$PWD/python_compat\${PYTHONPATH:+:\$PYTHONPATH}"; echo "MSMS_EXE=\${MSMS_EXE:-not found}" >&4; command -v pymol >&4 2>&4 || true; command -v mk_prepare_receptor.py >&4 2>&4 || true; command -v enzywizard-batch >&4 2>&4 || true; python -c 'import importlib.util, os, sys, numpy as np; print("HOME=", os.environ.get("HOME")); print("QT_QPA_PLATFORM=", os.environ.get("QT_QPA_PLATFORM")); print("pymol module=", bool(importlib.util.find_spec("pymol"))); print("pyvol module=", bool(importlib.util.find_spec("pyvol"))); print("numpy float_ shim=", hasattr(np, "float_")); print("rdkit.six shim=", "rdkit.six" in sys.modules)' >&4 2>&4 || true;
#set $input_name = $input_path.element_identifier #set $msa_name = $input_msa.element_identifier ln -s '$input_path' '$input_name' && ln -s '$input_msa' '$msa_name' && enzywizard-batch -i '$input_name' -m '$msa_name' #if $advanced.substrate_names: -s '$advanced.substrate_names' #end if $advanced.save_extra_outputs --hydrocluster_cutoff '$advanced.hydrocluster_cutoff' $advanced.no_minimize_energy --energy_minimization_iteration '$advanced.minimization_iteration' --flexibility_method '$advanced.flexibility_method' --flexibility_cutoff '$advanced.flexibility_cutoff' --flexibility_n_modes '$advanced.flexibility_n_modes' --disorder_window_size '$advanced.disorder_window_size' --disorder_min_region_length '$advanced.disorder_min_region_length' --embedding_model_name '$advanced.embedding_model_name' --pocket_min_rad '$advanced.pocket_min_rad' --pocket_max_rad '$advanced.pocket_max_rad' --pocket_min_volume '$advanced.pocket_min_volume' --substrate_max_synonyms '$advanced.substrate_max_synonyms' --substrate_fp_radius '$advanced.substrate_fp_radius' --substrate_n_bits '$advanced.substrate_n_bits' --substrate_num_confs '$advanced.substrate_num_confs' --substrate_prune_rms '$advanced.substrate_prune_rms' --dock_max_attempt_num '$advanced.dock_max_attempt_num' $advanced.dock_no_early_stop --dock_exhaustiveness '$advanced.dock_exhaustiveness' --dock_cpu "\${GALAXY_SLOTS:-1}" #if $advanced.dock_catalytic_residue: --dock_catalytic_residue '$advanced.dock_catalytic_residue' #end if #if $advanced.dock_catalytic_site_coord: --dock_catalytic_site_coord '$advanced.dock_catalytic_site_coord' #end if #if $advanced.dock_box_size: --dock_box_size '$advanced.dock_box_size' #end if --hbond_bonded_h_min_distance '$advanced.hbond_bonded_h_min_distance' --hbond_bonded_h_max_distance '$advanced.hbond_bonded_h_max_distance' --hbond_da_max_distance '$advanced.hbond_da_max_distance' --hbond_ha_max_distance '$advanced.hbond_ha_max_distance' --hbond_angle '$advanced.hbond_angle' --ionic_distance_cutoff '$advanced.ionic_distance_cutoff' --vdw_mu '$advanced.vdw_mu' --ppstack_center_distance_cutoff '$advanced.ppstack_center_distance_cutoff' --pication_distance_cutoff '$advanced.pication_distance_cutoff' --pication_angle_cutoff '$advanced.pication_angle_cutoff' --ssbond_max_distance '$advanced.ssbond_max_distance' -o ./ ; status=\$?; echo "---- files in Galaxy job working directory ----" >&4; find . -maxdepth 4 -type f | sort >&4; if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi; if ! find . -maxdepth 2 -type f \( -name 'integrate_report*.json' -o -name 'integrate_nodes*.json' -o -name 'integrate_edges*.json' \) | grep -q .; then echo "No EnzyWizard Batch integrate output files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
